# Battle Arena
import random

class Fighter:
    def __init__(self, name, hp, atk):
        self.name = name
        self.hp = hp
        self.atk = atk
        self.alive = True

    def attack(self, target):
        dmg = random.randint(1, self.atk)
        target.hp -= dmg
        if target.hp <= 0:
            target.alive = False
        return dmg

class Arena:
    def __init__(self):
        self.fighters = []
        self.round = 0

    def add(self, fighter):
        self.fighters.append(fighter)

    def battle(self):
        self.round += 1
        alive = [f for f in self.fighters
                 if f.alive]
        if len(alive) < 2:
            return alive[0] if alive else None
        a, b = random.sample(alive, 2)
        a.attack(b)
        return None

    def champion(self):
        alive = [f for f in self.fighters
                 if f.alive]
        return alive[0].name if alive else None
